#!/usr/bin/env python3
"""Leadger — Railway + Supabase deployment."""
import http.server, socketserver, os, base64 as _b64

PORT = int(os.environ.get("PORT", 8765))

HTML    = _b64.b64decode("").decode("utf-8")
LANDING = _b64.b64decode("").decode("utf-8")

import json as _j2
from urllib.parse import urlparse

class H(http.server.BaseHTTPRequestHandler):
    def do_GET(self):
        path = urlparse(self.path).path.rstrip('/')
        if path == "/health": self._h()
        elif path == "/app":  self._a()
        elif path == "":      self._l()
        else:                 self._a()
    def do_POST(self):
        if self.path=="/export": self._e()
        else: self.send_response(200); self._c(); self.end_headers(); self.wfile.write(b"ok")
    def do_OPTIONS(self): self.send_response(200); self._c(); self.end_headers()
    def _c(self):
        self.send_header("Access-Control-Allow-Origin","*")
        self.send_header("Access-Control-Allow-Methods","GET,POST,OPTIONS")
        self.send_header("Access-Control-Allow-Headers","Content-Type")
    def _h(self):
        self.send_response(200); self.send_header("Content-Type","application/json")
        self._c(); self.end_headers(); self.wfile.write(b'{"status":"ok"}')
    def _l(self):
        self.send_response(200); self.send_header("Content-type","text/html; charset=utf-8")
        self.send_header("Cache-Control","public, max-age=3600"); self._c(); self.end_headers()
        self.wfile.write(LANDING.encode("utf-8"))
    def _a(self):
        self.send_response(200); self.send_header("Content-type","text/html; charset=utf-8")
        self.send_header("Cache-Control","no-cache"); self._c(); self.end_headers()
        self.wfile.write(HTML.encode("utf-8"))
    def _e(self):
        try:
            length=int(self.headers.get("Content-Length",0)); body=self.rfile.read(length)
            payload=_j2.loads(body); content=payload.get("content",""); fname=payload.get("filename","export.csv")
            self.send_response(200); self.send_header("Content-Type","text/csv; charset=utf-8-sig")
            self.send_header("Content-Disposition",f'attachment; filename="{fname}"'); self._c(); self.end_headers()
            self.wfile.write(content.encode("utf-8-sig"))
        except Exception as ex: self.send_response(500); self._c(); self.end_headers(); self.wfile.write(str(ex).encode())
    def log_message(self,f,*a): pass

def main():
    socketserver.TCPServer.allow_reuse_address = True
    with socketserver.TCPServer(("0.0.0.0", PORT), H) as h:
        print(f"Leadger running on port {PORT}")
        h.serve_forever()

if __name__ == "__main__": main()
